const inputData = $input.first().json || {};
const data = inputData.data;
let prompt = inputData.prompt || "";

// Regex để tìm các mẫu {{ key }} hoặc {{key}}
// [\w]+ khớp với các ký tự chữ, số và gạch dưới
prompt = prompt.replace(/\{\{\s*([\w]+)\s*\}\}/g, (match, key) => {

  // Kiểm tra xem key có tồn tại trong object 'data' không
  if (data.hasOwnProperty(key)) {
    const value = data[key];

    // Nếu dữ liệu là mảng (ví dụ: keywords), nối chúng bằng dấu phẩy
    if (Array.isArray(value)) {
      return value.join(", ");
    }

    // Nếu là chuỗi hoặc số, trả về giá trị
    return value;
  }

  // Nếu không tìm thấy key trong data, giữ nguyên placeholder (để dễ debug)
  return match;
});


return { prompt };

